type RpgMutation struct {
	config
	op                             Op
	typ                            string
	id                             *int
	createTime                     *time.Time
	updateTime                     *time.Time
	isDelete                       *bool
	version                        *int
	addversion                     *int
	uid                            *int
	adduid                         *int
	exp                            *int
	addexp                         *int
	level                          *int
	addlevel                       *int
	lifeValue                      *int
	addlifeValue                   *int
	lastSignDate                   *time.Time
	totalSignDays                  *int
	addtotalSignDays               *int
	consecutiveSignDays            *int
	addconsecutiveSignDays         *int
	banStartTime                   *time.Time
	banEndTime                     *time.Time
	sensitiveHitsCount             *int
	addsensitiveHitsCount          *int
	zeroLifeCount                  *int
	addzeroLifeCount               *int
	lotteryTickets                 *int
	addlotteryTickets              *int
	reputation                     *int
	addreputation                  *int
	lotteryPityCounter             *int
	addlotteryPityCounter          *int
	effectJson                     *string
	lotteryLegendaryPityCounter    *int
	addlotteryLegendaryPityCounter *int
	clearedFields                  map[string]struct{}
	done                           bool
	oldValue                       func(context.Context) (*Rpg, error)
	predicates                     []predicate.Rpg
}

var _ ent.Mutation = (*RpgMutation)(nil)

// rpgOption allows management of the mutation configuration using functional options.
type rpgOption func(*RpgMutation)

// newRpgMutation creates new mutation for the Rpg entity.
func newRpgMutation(c config, op Op, opts ...rpgOption) *RpgMutation {
	m := &RpgMutation{
		config:        c,
		op:            op,
		typ:           TypeRpg,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withRpgID sets the ID field of the mutation.
func withRpgID(id int) rpgOption {
	return func(m *RpgMutation) {
		var (
			err   error
			once  sync.Once
			value *Rpg
		)
		m.oldValue = func(ctx context.Context) (*Rpg, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().Rpg.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withRpg sets the old Rpg of the mutation.
func withRpg(node *Rpg) rpgOption {
	return func(m *RpgMutation) {
		m.oldValue = func(context.Context) (*Rpg, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

// Client returns a new `ent.Client` from the mutation. If the mutation was
// executed in a transaction (ent.Tx), a transactional client is returned.
func (m RpgMutation) Client() *Client {
	client := &Client{config: m.config}
	client.init()
	return client
}

// Tx returns an `ent.Tx` for mutations that were executed in transactions;
// it returns an error otherwise.
func (m RpgMutation) Tx() (*Tx, error) {
	if _, ok := m.driver.(*txDriver); !ok {
		return nil, errors.New("ent: mutation is not running in a transaction")
	}
	tx := &Tx{config: m.config}
	tx.init()
	return tx, nil
}

