// Where appends a list predicates to the RpgMutation builder.
func (m *RpgMutation) Where(ps ...predicate.Rpg) {
	m.predicates = append(m.predicates, ps...)
}

// WhereP appends storage-level predicates to the RpgMutation builder. Using this method,
// users can use type-assertion to append predicates that do not depend on any generated package.
func (m *RpgMutation) WhereP(ps ...func(*sql.Selector)) {
	p := make([]predicate.Rpg, len(ps))
	for i := range ps {
		p[i] = ps[i]
	}
	m.Where(p...)
}

