// rpgactivityOption allows management of the mutation configuration using functional options.
type rpgactivityOption func(*RpgActivityMutation)

// newRpgActivityMutation creates new mutation for the RpgActivity entity.
func newRpgActivityMutation(c config, op Op, opts ...rpgactivityOption) *RpgActivityMutation {
	m := &RpgActivityMutation{
		config:        c,
		op:            op,
		typ:           TypeRpgActivity,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withRpgActivityID sets the ID field of the mutation.
func withRpgActivityID(id int) rpgactivityOption {
	return func(m *RpgActivityMutation) {
		var (
			err   error
			once  sync.Once
			value *RpgActivity
		)
		m.oldValue = func(ctx context.Context) (*RpgActivity, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().RpgActivity.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withRpgActivity sets the old RpgActivity of the mutation.
func withRpgActivity(node *RpgActivity) rpgactivityOption {
	return func(m *RpgActivityMutation) {
		m.oldValue = func(context.Context) (*RpgActivity, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

